int main() {
    int size = 0;
    cout << "Enter the size of the array: ";
    cin >> size;
    int myArray[size];
    cout << "Enter " << size << " integers in any order: ";
    for (int i = 0; i < size; i++) {
        cin >> myArray[i];
    }
    cout << "Before sorting" << endl;
    for (int i = 0; i < size; i++) {
        cout << myArray[i] << " ";
    }
    cout << endl;
    quicksort(myArray, 0, size - 1);
    cout << "After sorting" << endl;
    for (int i = 0; int i < size; i++) {
        cout << myArray[i] << " ";
    }
    cout << endl;
    return 0;
}

void quicksort(int arr[], int s, int e) {
    if (s < e) {
        int p = partition(arr, s, e);
        quicksort(arr, s, p - 1);
        quicksort(arr, p + 1, e);
    }
}

int partition(int arr[], int s, int e) {
    int pivot = arr[e];
    int i = s - 1;
    for (int j = s; j < e; j++) {
        if (arr[j] <= pivot) {
            i++;
            int temp = arr[i];
            arr[i] = arr[j];
            arr[j] = temp;
        }
    }
    int temp = arr[i + 1];
    arr[i + 1] = arr[e];
    arr[e] = temp;
    return i + 1;
}

