// Object oriented programming.
// Polymorphism means "many forms", and it occurs when we have many classes that are related to each other by inheritance.

class YouTubeChannel
{
private:
	string Name;
	int SubscriberCount;
	list<string> PublishedVideoTitles;

protected:
	string OwnerName;
	int ContentQuality;

public:
	YouTubeChannel(string name, string ownername)
	{
		Name = name;
		OwnerName = ownername;
		SubscriberCount = 0;
		ContentQuality = 0;
	}

	void GetInfo()
	{
		cout
			<< "Name: " << Name << endl
			<< "OwnerName: " << OwnerName << endl
			<< "SubscriberCount: " << SubscriberCount << endl
			<< "PublishedVideoTitles: " << endl;
		for (string VideoTitles : PublishedVideoTitles)
		{
			cout << VideoTitles << endl;
		}
	}

	void Subscribe()
	{
		SubscriberCount++;
	}

	void UnSubscribe()
	{
		if (SubscriberCount > 0)
			SubscriberCount--;
	}

	void PublishVideo(string title)
	{
		PublishedVideoTitles.push_back(title);
	}

	void CheckAnalytics()
	{
		if (ContentQuality < 5)
			cout << Name << " has bad quality content." << endl;
		else
			cout << Name << " has great quality content." << endl;
	}
};

// Derived Class, Inheriting from YouTubeChannel.
class CookingYouTubeChannel : public YouTubeChannel
{
