	SingersYouTubeChannel(string Name, string OwnerName) : YouTubeChannel(Name, OwnerName)
	{

	}

	void Practice()
	{
		cout << OwnerName << " is taking singing classes, learning new songs, learning how to dance..." << endl;
		ContentQuality++;
	}
};

